-- PostgreSQL: books table (rigid schema)
CREATE TABLE books (
  id SERIAL PRIMARY KEY,
  title VARCHAR(255),
  published_year INT,
  price DECIMAL(6,2)
);

// MongoDB: books collection (flexible)
{
  _id: ObjectId("..."),
  title: "1984",
  publishedYear: 1949,
  price: 12.99,
  genres: ["dystopia", "classic"],   // arrays are native!
  author: {                           // embedded objects too!
    name: "George Orwell",
    nationality: "British"
  }
}

const session = client.startSession();
try {
  session.startTransaction();
  await accounts.updateOne({ _id: fromId }, { $inc: { balance: -100 } }, { session });
  await accounts.updateOne({ _id: toId },   { $inc: { balance: +100 } }, { session });
  await session.commitTransaction();
} catch (e) {
  await session.abortTransaction();  // rolls back both updates
} finally {
  session.endSession();
}

// Create a capped collection that holds at most 1000 documents
db.createCollection('logs', { capped: true, size: 10485760, max: 1000 })
// size = max bytes, max = max documents
// Oldest document is automatically removed when limit is hit
